export async function evaluateFile(
  task: ReviewTask, axes: AxisEvaluator[], ctx: EvalContext,
): Promise<ReviewFile> {
  const results: AxisResult[] = [];
  for (const axis of axes) {
    try {
      const result = await retryWithBackoff(() => axis.evaluate(task, ctx), {
        maxRetries: 2, baseDelayMs: 1000,
      });
      results.push(result);
      ctx.onAxisComplete?.(task.file, axis.id, result);
    } catch (err) {
      ctx.logger.warn({ axis: axis.id, file: task.file, err }, 'axis evaluation failed');
      results.push({ axisId: axis.id, symbols: [], error: String(err) });
    }
  }
  const merged = mergeAxisResults(task, results, ctx.usageGraph);
  if (needsDeliberation(merged)) {
    const deliberation = await runDeliberation(merged, task, ctx);
    return applyDeliberation(merged, deliberation);
  }
  return merged;
}

export class ProgressManager {
  private progress: ProgressData;
  private writeQueue: Promise<void> = Promise.resolve();
  private dirty = false;

  constructor(private progressPath: string) {
    this.progress = existsSync(progressPath)
      ? JSON.parse(readFileSync(progressPath, 'utf-8'))
      : { version: 1, files: {}, startedAt: new Date().toISOString() };
  }

  updateFileStatus(file: string, status: FileStatus, verdict?: Verdict): void {
    this.progress.files[file] = {
      status,
      verdict,
      updatedAt: new Date().toISOString(),
    };
    this.dirty = true;
    this.writeQueue = this.writeQueue.then(() =>
      atomicWriteJson(this.progressPath, this.progress)
    );
  }

  getFileStatus(file: string): FileStatus | undefined {
    return this.progress.files[file]?.status;
  }

  getAllFiles(): Record<string, { status: FileStatus; verdict?: Verdict }> {
    return this.progress.files;
  }

  async flush(): Promise<void> {
    await this.writeQueue;
    this.dirty = false;
  }
}

export function mergeSymbol(
  symbolName: string,
  axisResults: Map<AxisId, AxisSymbolResult>,
  usageGraph: UsageGraph,
): MergedSymbol {
  const correction = axisResults.get('correction')?.correction ?? '-';
  const utility = axisResults.get('utility')?.utility ?? '-';
  const duplication = axisResults.get('duplication')?.duplication ?? '-';
  const overengineering = axisResults.get('overengineering')?.overengineering ?? '-';
  const tests = axisResults.get('tests')?.tests ?? '-';

  // Inter-axis coherence rules
  const adjustedTests = utility === 'DEAD' ? 'NONE' : tests;
  const adjustedOE = correction === 'ERROR' ? 'ACCEPTABLE' : overengineering;

  const confidences = Array.from(axisResults.values())
    .map(r => r.confidence)
    .filter(c => c > 0);
  const confidence = confidences.length > 0 ? Math.min(...confidences) : 50;

  return {
    name: symbolName,
    correction,
    utility,
    duplication,
    overengineering: adjustedOE,
    tests: adjustedTests,
    confidence,
    detail: buildMergedDetail(axisResults),
  };
}

export function loadConfig(projectRoot: string): Config {
  const configPath = resolve(projectRoot, 'anatoly.config.yaml');
  if (!existsSync(configPath)) {
    return getDefaultConfig();
  }
  const raw = readFileSync(configPath, 'utf-8');
  const parsed = yaml.parse(raw);
  const result = ConfigSchema.safeParse(parsed);
  if (!result.success) {
    const issues = result.error.issues.map(
      i => `  ${i.path.join('.')}: ${i.message}`
    );
    throw new Error(`Invalid anatoly.config.yaml:\n${issues.join('\n')}`);
  }
  const config = result.data;
  // Environment variable overrides
  if (process.env.ANATOLY_CONCURRENCY) {
    const val = parseInt(process.env.ANATOLY_CONCURRENCY, 10);
    if (!isNaN(val) && val > 0) config.concurrency = val;
  }
  if (process.env.ANATOLY_MODEL) {
    config.model = process.env.ANATOLY_MODEL;
  }
  return config;
}

export function parseFile(filePath: string, content: string): ParsedFile {
  const lang = detectLanguage(filePath);
  const parser = getParser(lang);
  const tree = parser.parse(content);
  const symbols: Symbol[] = [];
  const cursor = tree.walk();
  let reachedRoot = false;

  while (!reachedRoot) {
    const node = cursor.currentNode;
    if (isExportedDeclaration(node) || isFunctionDeclaration(node)) {
      const name = extractName(node);
      const kind = classifyKind(node);
      if (name && kind) {
        symbols.push({
          name,
          kind,
          exported: isExported(node),
          line_start: node.startPosition.row + 1,
          line_end: node.endPosition.row + 1,
        });
      }
    }
    if (cursor.gotoFirstChild()) continue;
    if (cursor.gotoNextSibling()) continue;
    while (true) {
      if (!cursor.gotoParent()) { reachedRoot = true; break; }
      if (cursor.gotoNextSibling()) break;
    }
  }

  return {
    filePath,
    symbols,
    lineCount: content.split('\n').length,
    hash: computeHash(content),
  };
}

export async function searchByIdHybrid(
  store: VectorStore,
  functionId: string,
  k: number = 5,
  codeWeight: number = 0.6,
): Promise<SearchResult[]> {
  const card = await store.getById(functionId);
  if (!card) return [];

  const codeResults = await store.searchByVector(card.vector, k * 2, 'function');
  const nlpResults = card.nlp_vector
    ? await store.searchByNlpVector(card.nlp_vector, k * 2, 'function')
    : [];

  const scoreMap = new Map<string, { code: number; nlp: number }>();
  for (const r of codeResults) {
    if (r.id === functionId) continue;
    scoreMap.set(r.id, { code: r.score, nlp: 0 });
  }
  for (const r of nlpResults) {
    if (r.id === functionId) continue;
    const existing = scoreMap.get(r.id) ?? { code: 0, nlp: 0 };
    existing.nlp = r.score;
    scoreMap.set(r.id, existing);
  }

  return Array.from(scoreMap.entries())
    .map(([id, s]) => ({
      id,
      score: codeWeight * s.code + (1 - codeWeight) * s.nlp,
    }))
    .sort((a, b) => b.score - a.score)
    .slice(0, k);
}

export function generateReport(
  projectRoot: string,
  errorFiles: string[],
  runDir?: string,
): { reportPath: string; data: ReportData } {
  const reviewsDir = runDir
    ? resolve(runDir, 'reviews')
    : resolve(projectRoot, '.anatoly', 'reviews');
  const reviews = loadReviews(reviewsDir);
  const globalVerdict = computeGlobalVerdict(reviews);
  const findingFiles = reviews.filter(r => r.verdict !== 'CLEAN');
  const cleanFiles = reviews.filter(r => r.verdict === 'CLEAN');

  const data: ReportData = {
    totalFiles: reviews.length,
    findingFiles,
    cleanFiles,
    errorFiles,
    globalVerdict,
    generatedAt: new Date().toISOString(),
  };

  const markdown = renderIndex(data);
  const shards = renderShards(data);
  const reportPath = runDir
    ? resolve(runDir, 'report.md')
    : resolve(projectRoot, '.anatoly', 'report.md');

  writeFileSync(reportPath, markdown, 'utf-8');
  for (let i = 0; i < shards.length; i++) {
    writeFileSync(reportPath.replace('.md', `.${i + 1}.md`), shards[i], 'utf-8');
  }

  return { reportPath, data };
}

async function runWorkerPool<T>(
  tasks: T[],
  concurrency: number,
  worker: (task: T, index: number) => Promise<void>,
  onProgress?: (completed: number, total: number) => void,
): Promise<void> {
  let nextIndex = 0;
  let completed = 0;
  const total = tasks.length;
  const errors: Error[] = [];

  async function runNext(): Promise<void> {
    while (nextIndex < total) {
      const idx = nextIndex++;
      try {
        await worker(tasks[idx], idx);
      } catch (err) {
        errors.push(err instanceof Error ? err : new Error(String(err)));
      }
      completed++;
      onProgress?.(completed, total);
    }
  }

  const workers = Array.from(
    { length: Math.min(concurrency, total) },
    () => runNext(),
  );
  await Promise.all(workers);

  if (errors.length > 0) {
    throw new AggregateError(
      errors,
      `${errors.length}/${total} tasks failed`,
    );
  }
}

export function applyDeliberation(
  review: ReviewFile,
  deliberation: DeliberationResponse,
): { symbols: ReviewSymbol[]; verdict: Verdict; reclassified: number } {
  const symbols = review.symbols.map(sym => {
    const delib = deliberation.symbols.find(d => d.name === sym.name);
    if (!delib) return sym;

    const newConfidence = delib.deliberated.confidence ?? sym.confidence;
    const changes: string[] = [];
    const updated = { ...sym, confidence: newConfidence };

    const AXES = ['correction', 'utility', 'duplication', 'overengineering', 'tests'] as const;
    for (const axis of AXES) {
      const orig = delib.original[axis];
      const deliberated = delib.deliberated[axis];
      if (!orig || !deliberated) continue;
      if (orig !== deliberated) {
        changes.push(`${axis}: ${orig} -> ${deliberated}`);
      }
      setAxisValue(updated, axis, deliberated);
    }

    const changesSummary = changes.length > 0
      ? ` (deliberated: reclassified ${changes.join(', ')})`
      : ` (deliberated: confirmed)`;
    updated.detail = (updated.detail ?? '') + changesSummary;
    return updated;
  });

  const verdict = recomputeVerdict(symbols, deliberation.verdict);
  const reclassified = deliberation.symbols.filter(s =>
    AXES.some(axis => s.original[axis] !== s.deliberated[axis]),
  ).length;

  return { symbols, verdict, reclassified };
}

const NAMED_IMPORT_RE = /import\s*\{([^}]+)\}\s*from\s*['"]([^'"]+)['"]/g;
const DEFAULT_IMPORT_RE = /import\s+(\w+)\s+from\s*['"]([^'"]+)['"]/g;
const STAR_REEXPORT_RE = /export\s+\*\s+from\s*['"]([^'"]+)['"]/g;

export function extractImports(content: string, filePath: string): ImportEdge[] {
  const edges: ImportEdge[] = [];
  const dir = dirname(filePath);

  for (const re of [NAMED_IMPORT_RE, DEFAULT_IMPORT_RE]) {
    let match: RegExpExecArray | null;
    while ((match = re.exec(content)) !== null) {
      const specifier = match[match.length - 1];
      if (specifier.startsWith('.')) {
        const resolved = resolveRelative(dir, specifier);
        const symbols = match.length === 3
          ? parseNamedSymbols(match[1])
          : [match[1]];
        edges.push({
          from: filePath,
          to: resolved,
          symbols,
          isTypeOnly: /^import\s+type/.test(match[0]),
        });
      }
    }
  }

  let starMatch;
  while ((starMatch = STAR_REEXPORT_RE.exec(content)) !== null) {
    const specifier = starMatch[1];
    if (specifier.startsWith('.')) {
      edges.push({
        from: filePath,
        to: resolveRelative(dir, specifier),
        symbols: ['*'],
        isTypeOnly: false,
      });
    }
  }

  return edges;
}
